// Extraire les donnees du webhook Evolution API
const body = $input.first().json.body || $input.first().json;

// Evolution API envoie les messages dans data.message
const data = body.data || body;
const message = data.message || {};

// Extraire le texte du message
let text = '';
if (message.conversation) {
  text = message.conversation;
} else if (message.extendedTextMessage) {
  text = message.extendedTextMessage.text;
} else if (typeof message === 'string') {
  text = message;
}

// Extraire le numero (remoteJid sans @s.whatsapp.net)
const remoteJid = data.key?.remoteJid || data.remoteJid || '';
const phone = remoteJid.replace('@s.whatsapp.net', '');

// Extraire le pushName
const pushName = data.pushName || 'Client';

// Ignorer les messages sortants (fromMe)
const fromMe = data.key?.fromMe || false;

if (fromMe || !text || !phone) {
  return []; // Ignorer
}

return [{
  json: {
    phone,
    message: text,
    pushName,
    remoteJid
  }
}];

const input = $input.first().json;

// Si erreur, utiliser le message fallback
let reply = input.reply;
if (!reply || input.error) {
  reply = 'Desole, je rencontre un petit souci technique. Un conseiller va vous repondre tres vite.';
}

// Recuperer le numero depuis le noeud d'extraction
const extractNode = $node["Code - Extraire Donnees"];
const phone = input.phone || extractNode.json.phone;
const remoteJid = extractNode.json.remoteJid || phone + '@s.whatsapp.net';

return [{
  json: {
    reply,
    phone,
    remoteJid
  }
}];

// Fallback en cas d'erreur sur l'appel agent
const extractNode = $node["Code - Extraire Donnees"];
const phone = extractNode.json.phone;
const remoteJid = extractNode.json.remoteJid || phone + '@s.whatsapp.net';

return [{
  json: {
    reply: 'Desole, je rencontre un petit souci technique. Un conseiller va vous repondre tres vite.',
    phone,
    remoteJid
  }
}];
